SELECT r.raceid, r.name AS race_name, ci.country, rs.points, c.name AS constructor_name, c.nationality FROM races AS r JOIN circuits AS ci ON r.circuitid = ci.circuitid JOIN results AS rs ON r.raceid = rs.raceid JOIN constructors AS c ON rs.constructorid = c.constructorid WHERE (ci.country = 'Australia') AND (rs.positionorder <= 10) AND (rs.points > 0) AND (c.nationality IN ('British', 'French', 'German', 'Spanish', 'Italian', 'Austrian', 'Swedish', 'Dutch', 'Belgian')) GROUP BY r.raceid, r.name, ci.country, rs.points, c.name, c.nationality HAVING (rs.points > 0)
